/**
 * BFF Dashboard 主页（裂变主页）
 * - 路由：/bff-dashboard
 * - 初始态：未邀请用户，展示里程碑奖励
 * - 后续态：有被邀请者，展示 Locked Bonus + Squad 列表
 */

import { useEffect, useCallback, useState, useRef, Fragment } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useBffDashboard } from "@/hooks/useBff";
import { getBffDashboard } from "@/api/bff";
import { shareBffLink } from "@/utils/bffShare";
import { bpTrack } from "@/tracking/api/byteplus";
import { EventName } from "@/tracking/events";
import Spinner from "@/components/Spinner";
import Lottie from "lottie-react";
import { showCashoutModal } from "@/components/showCashoutModal";
import type { SquadMember, StageProgressItem, BffDashboard as BffDashboardType, BffStage } from "@/types/bff";
import {
  SQUAD_BG_IMAGES,
  SQUAD_BTN_COLORS,
  SQUAD_STAGE_COLORS,
  SQUAD_SECOND_STAGE_CIRCLE_COLORS,
  STAGE_COPY_CONFIG,
  STAGE_ANIMATION_DELTA,
  MILESTONES,
  BFF_LANDING_PATH,
} from "@/constants/bff";

import icBackWhite from "@/assets/images/common/ic_back_white.svg";
import icCopy from "@/assets/images/bff/ic_copy.svg";
import bgDashboardTop from "@/assets/images/bff/bg_dashboard_top.png";
import icWallet from "@/assets/images/bff/ic_wallet.png";
import icLockWarning from "@/assets/images/bff/ic_lock_warning.png";
import icStatusLost from "@/assets/images/bff/ic_status_lost.png";
import icStatusUrgent from "@/assets/images/bff/ic_status_urgent.png";
import icStatusInactive from "@/assets/images/bff/ic_status_inactive.png";
import icStatusActive from "@/assets/images/bff/ic_status_active.png";
import icArrowTriangle from "@/assets/images/bff/ic_arrow_triangle.png";
import icMilestone1 from "@/assets/images/bff/ic_milestone_1.png";
import icMilestone5 from "@/assets/images/bff/ic_milestone_5.png";
import icMilestone10 from "@/assets/images/bff/ic_milestone_10.png";
import icMilestoneUnlimited from "@/assets/images/bff/ic_milestone_unlimited.png";
import icCopySuccess from "@/assets/images/bff/ic_copy_success.png";
import icEventRulesHelp from "@/assets/images/bff/ic_event_rules_help.png";
import { showEventRulesModal } from "@/components/EventRulesModal";

/**
 * 生成 Push 动画去重的 localStorage key。
 * 格式：bff_anim_seen:{relationId}:{stage}
 * 例：bff_anim_seen:123456:W4
 */
const getAnimSeenKey = (rid: string, stage: string) => `bff_anim_seen:${rid}:${stage}`;

export const BffDashboard = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { dashboard, loading, setDashboard, setLoading, setError } = useBffDashboard();
  const [showCopyToast, setShowCopyToast] = useState(false);
  const copyToastTimer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
  const [showCoinAnimation, setShowCoinAnimation] = useState(false);
  const [moneyAnimationData, setMoneyAnimationData] = useState<Record<string, unknown> | null>(null);

  /**
   * Push 动画的奖励金额（delta）。
   * - 来自 Push 链接时：由 STAGE_ANIMATION_DELTA 根据阶段推导
   * - 来自后端 hasPendingCoinAnimation 时：由 dashboard.animationRewardDelta 提供
   * 两路互斥，Push 优先
   */
  const [pendingAnimDelta, setPendingAnimDelta] = useState(0);

  /**
   * 用 ref 保存当前 Push 触发的 {rid, stage}。
   * 不用 state 的原因：URL 参数在 useEffect 中会被立即清除，
   * 但 onAnimationEnd 回调在动画结束（约 1800ms）后才执行，
   * 此时 searchParams 已清空。ref 可跨渲染持久保存直到动画结束。
   */
  const pendingAnimRef = useRef<{ rid: string; stage: string } | null>(null);

  // 构建邀请链接 - 从 dashboard 接口获取 inviteCode
  const inviteUrl = `${window.location.origin}${BFF_LANDING_PATH}?c=${dashboard?.inviteCode || ""}`;

  useEffect(() => {
    fetch("/animations/onboarding_money.json")
      .then((res) => res.json())
      .then((data) => setMoneyAnimationData(data))
      .catch((err) => console.error("Failed to load animation:", err));
  }, []);

  /**
   * 解析并清除 Push 通知携带的 URL 参数。
   *
   * Push 链接格式：/bff-dashboard?rid={relationId}&stage={W3|W4|W5}
   *   - rid:   被邀请人的 relationId
   *   - stage: 她刚完成的阶段，用于推导奖励金额
   *
   * 解析完立即用 replace 清除参数，避免：
   *   1. 用户刷新页面重复触发动画
   *   2. 分享给别人的 URL 携带他人的 rid
   *
   * 依赖数组故意为空：只在挂载时执行一次，searchParams 不加入依赖，
   * 否则 setSearchParams 会触发重新执行形成死循环。
   */
  useEffect(() => {
    const rid = searchParams.get("rid");
    const stage = searchParams.get("stage");
    if (rid && stage) {
      // 将 {rid, stage} 写入 ref，供后续 fetchDashboard 和 onAnimationEnd 使用
      pendingAnimRef.current = { rid, stage };
      // 立即清除 URL 参数，不留在地址栏
      navigate(window.location.pathname, { replace: true });
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const fetchDashboard = useCallback(async () => {
    try {
      setLoading(true);
      const data = await getBffDashboard();
      setDashboard(data);

      const pending = pendingAnimRef.current;
      if (pending) {
        /**
         * Push 触发路径：URL 携带了 rid + stage
         * 1. 检查 localStorage 是否已播放过该 (rid, stage) 的动画
         * 2. 未播放 → 从 STAGE_ANIMATION_DELTA 推导奖励金额，触发动画
         * 3. 已播放 → 静默跳过，不重复展示
         */
        const key = getAnimSeenKey(pending.rid, pending.stage);
        if (!localStorage.getItem(key)) {
          const delta = STAGE_ANIMATION_DELTA[pending.stage as BffStage] ?? 0;
          if (delta > 0) {
            setPendingAnimDelta(delta);
            setShowCoinAnimation(true);
            bpTrack(EventName.bff_coin_animation_play);
          }
        }
      } else if (data.hasPendingCoinAnimation) {
        /**
         * 后端触发路径：非 Push 进入但后端标记了待播动画
         * （兼容原有逻辑，delta 由 dashboard.animationRewardDelta 提供）
         */
        bpTrack(EventName.bff_coin_animation_play);
        setShowCoinAnimation(true);
      }
    } catch (err) {
      console.error("[BffDashboard] Failed to fetch:", err);
      setError("Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  }, [setDashboard, setLoading, setError]);

  useEffect(() => {
    fetchDashboard();
  }, [fetchDashboard]);

  /**
   * 飞钱动画结束回调。
   *
   * Push 触发时：将 (rid, stage) 写入 localStorage，标记该动画已播放。
   * 后续再次点击同一条 Push 链接时，fetchDashboard 检查到 key 存在，
   * 跳过动画触发，确保每个 (rid, stage) 组合只播一次。
   *
   * 后端触发时：pendingAnimRef 为空，仅关闭动画状态即可。
   */
  const handleAnimationEnd = useCallback(() => {
    setShowCoinAnimation(false);
    const pending = pendingAnimRef.current;
    if (pending) {
      localStorage.setItem(getAnimSeenKey(pending.rid, pending.stage), "1");
      pendingAnimRef.current = null;
    }
  }, []);

  const handleShare = useCallback(async () => {
    if (!dashboard) return;
    await shareBffLink({
      text: dashboard.shareText,
      url: inviteUrl,
    });
    bpTrack(EventName.bff_share_trigger);
  }, [dashboard, inviteUrl]);

  const handleCopyLink = useCallback(async () => {
    if (!dashboard) return;
    try {
      await navigator.clipboard.writeText(inviteUrl);
    } catch (err) {
      console.warn("[CopyLink] clipboard API failed, using fallback:", err);
      try {
        const textarea = document.createElement("textarea");
        textarea.value = inviteUrl;
        textarea.style.position = "fixed";
        textarea.style.opacity = "0";
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand("copy");
        document.body.removeChild(textarea);
      } catch (e) {
        console.error("[CopyLink] fallback also failed:", e);
      }
    }
    clearTimeout(copyToastTimer.current);
    setShowCopyToast(true);
    copyToastTimer.current = setTimeout(() => setShowCopyToast(false), 2000);
  }, [dashboard, inviteUrl]);

  if (loading && !dashboard) {
    return (
      <div
        className="flex items-center justify-center h-screen"
        style={{ background: "linear-gradient(135deg, #7EC8E3, #A8DAEF)" }}
      >
        <Spinner size={48} color="#7EC8E3" />
      </div>
    );
  }

  if (!dashboard) {
    return (
      <div
        className="flex items-center justify-center h-screen"
        style={{ background: "linear-gradient(135deg, #7EC8E3, #A8DAEF)" }}
      >
        <div className="text-center">
          <p className="text-white/80 mb-4">Failed to load dashboard</p>
          <button onClick={() => navigate(-1)} className="px-6 py-2 bg-white/20 text-white rounded-lg">
            Go Back
          </button>
        </div>
      </div>
    );
  }

  const hasSquadMembers = dashboard.squadList.length > 0;

  return (
    <div>
      <div
        className="min-h-screen flex flex-col"
        style={{ background: `url(${bgDashboardTop})`, backgroundSize: "contain" }}
      >
        {/* ========== 顶部背景区 ========== */}
        <div className="relative flex-shrink-0">
          {/* 导航栏 */}
          <div
            className="relative z-10 flex items-center h-[52px] px-4"
            style={{ marginTop: "max(env(safe-area-inset-top), 40px)" }}
          >
            <button onClick={() => navigate(-1)} className="w-6 h-6">
              <img src={icBackWhite} alt="back" className="w-6 h-6" />
            </button>
            <p className="flex-1 text-center text-white text-[16px] font-medium tracking-[-0.23px] leading-[21px] font-['Pangram']">
              BFF Creator Program
            </p>
            <button
              type="button"
              aria-label="Open event rules"
              className="w-6 h-6 flex items-center justify-center"
              onClick={showEventRulesModal}
            >
              <img src={icEventRulesHelp} alt="help" className="w-6 h-6" />
            </button>
          </div>

          {/* Hero 文案 - 仅未邀请态展示 */}
          {!hasSquadMembers && (
            <div className="relative z-10 px-4 mt-4 sm:mt-5 md:mt-6">
              <h1 className="text-[28px] font-bold leading-[35px] tracking-[-0.32px] text-white font-['Pangram']">
                {dashboard.defaultCopy || `Earn $${dashboard.defaultReward?.rewardAmount ?? 60} for EVERY friend!`}
              </h1>
              <p className="mt-2 text-[15px] leading-[20.6px] tracking-[-0.23px] text-white/[0.78] font-['Saans_TRIAL']">
                Invite your besties and you both get rewarded. The more friends join, the more you earn.
              </p>
            </div>
          )}
        </div>

        {/* ========== Locked Bonus 卡片 - 浮在蓝色背景上 ========== */}
        {hasSquadMembers && (
          <div className="relative z-10 mt-3">
            <LockedBonusCard
              dashboard={dashboard}
              playAnimation={showCoinAnimation}
              rewardDelta={
                // Push 触发时用前端推导的 delta；后端触发时用 API 返回的 animationRewardDelta
                pendingAnimDelta || (dashboard.animationRewardDelta ?? 0)
              }
              moneyAnimationData={moneyAnimationData}
              onAnimationEnd={handleAnimationEnd}
              onCashOut={() => showCashoutModal({ amount: dashboard.availableAmount.toFixed(2) })}
            />
          </div>
        )}

        {/* ========== 白色卡片区域 ========== */}
        <div
          className={`relative z-10 flex-1 ${hasSquadMembers ? "mt-4" : "mt-7 sm:mt-9 md:mt-10"} bg-white rounded-t-[16px]`}
        >
          {/* My Squad 标题 */}
          <div className="px-4 pt-4 pb-6">
            <p className="text-[15px] font-medium text-black tracking-[-0.23px] leading-5 font-['Pangram']">
              My Squad
              {hasSquadMembers ? `(${dashboard.squadList.length})` : ""}
            </p>
          </div>

          {/* 内容区：未邀请态→里程碑，邀请态→Squad 列表 */}
          <div className="px-4 pb-[160px] font-['Saans_TRIAL']">
            {hasSquadMembers ? (
              <SquadList dashboard={dashboard} inviteUrl={inviteUrl} />
            ) : (
              <MilestoneCard dashboard={dashboard} />
            )}
          </div>
        </div>
      </div>

      {/* 复制成功 toast */}
      {showCopyToast && (
        <div
          className="fixed left-0 right-0 z-50 px-4 animate-fade-in"
          style={{ top: "calc(max(env(safe-area-inset-top), 40px) + 52px)" }}
        >
          <div
            style={{
              display: "flex",
              padding: "14px 16px",
              alignItems: "flex-start",
              gap: "10px",
              borderRadius: "12px",
              backgroundColor: "#34C759",
            }}
          >
            <img src={icCopySuccess} alt="" className="w-[18px] h-[18px] shrink-0 mt-[1px]" />
            <span
              className="text-white font-['Saans_TRIAL']"
              style={{ fontSize: "15px", fontWeight: 400, lineHeight: "20px" }}
            >
              Link copied successfully, go share it quickly~
            </span>
          </div>
        </div>
      )}

      {/* ========== 底部固定操作栏 ========== */}
      <div
        className="fixed bottom-0 left-0 right-0 z-20"
        style={{
          backdropFilter: "blur(14px)",
          backgroundColor: "rgba(255,255,255,0.5)",
        }}
      >
        <div className="px-4 pt-4">
          <button
            onClick={handleShare}
            className="w-full h-[51px] bg-black rounded-full flex items-center justify-center"
          >
            <span className="text-white text-[16px] font-medium tracking-[-0.23px] leading-[21px] font-['Pangram']">
              {dashboard.buttonText}
            </span>
          </button>

          <button onClick={handleCopyLink} className="w-full h-[37px] flex items-center justify-center gap-[2px] mt-1">
            <span className="text-[#333] text-[13px] tracking-[-0.23px] leading-[18px] font-['Saans_TRIAL']">
              {inviteUrl}
            </span>
            <img src={icCopy} alt="copy" className="w-[12px] h-[12px]" />
          </button>
        </div>
        <div style={{ height: "max(env(safe-area-inset-bottom), 8px)" }} />
      </div>
    </div>
  );
};

// ==================== 滚动数字 Hook ====================

const useRollingNumber = (from: number, to: number, play: boolean, duration: number = 1200) => {
  const [display, setDisplay] = useState(from);

  useEffect(() => {
    if (!play) {
      setDisplay(from);
      return;
    }
    if (from === to) return;

    const startTime = performance.now();
    let raf: number;

    const tick = (now: number) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const ease = 1 - Math.pow(1 - progress, 3);
      setDisplay(Math.round(from + (to - from) * ease));
      if (progress < 1) {
        raf = requestAnimationFrame(tick);
      }
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [from, to, play, duration]);

  return display;
};

// ==================== Locked Bonus 卡片（邀请态顶部） ====================

const LockedBonusCard = ({
  dashboard,
  playAnimation,
  rewardDelta,
  moneyAnimationData,
  onAnimationEnd,
  onCashOut,
}: {
  dashboard: BffDashboardType;
  playAnimation: boolean;
  rewardDelta: number;
  moneyAnimationData: Record<string, unknown> | null;
  onAnimationEnd: () => void;
  onCashOut: () => void;
}) => {
  const lockedRef = useRef<HTMLDivElement>(null);
  const availableRef = useRef<HTMLDivElement>(null);
  const cardRef = useRef<HTMLDivElement>(null);
  const [flyStyle, setFlyStyle] = useState<React.CSSProperties | null>(null);

  const [availablePlay, setAvailablePlay] = useState(false);

  const displayLocked = useRollingNumber(
    dashboard.lockedAmount + rewardDelta,
    dashboard.lockedAmount,
    playAnimation,
    1000,
  );
  const displayAvailable = useRollingNumber(
    dashboard.availableAmount - rewardDelta,
    dashboard.availableAmount,
    availablePlay,
    600,
  );

  useEffect(() => {
    if (!playAnimation || rewardDelta <= 0) return;

    // Locked 减少 + 飞钱同时启动
    requestAnimationFrame(() => {
      if (lockedRef.current && availableRef.current && cardRef.current) {
        const cardRect = cardRef.current.getBoundingClientRect();
        const fromRect = lockedRef.current.getBoundingClientRect();
        const toRect = availableRef.current.getBoundingClientRect();

        setFlyStyle({
          "--start-x": `${fromRect.left - cardRect.left + fromRect.width / 2}px`,
          "--start-y": `${fromRect.top - cardRect.top + fromRect.height / 2}px`,
          "--end-x": `${toRect.left - cardRect.left + toRect.width / 2}px`,
          "--end-y": `${toRect.top - cardRect.top + toRect.height / 2}px`,
        } as React.CSSProperties);
      }
    });

    // 飞钱飞到一半时，Available 开始增加
    const t1 = setTimeout(() => {
      setAvailablePlay(true);
    }, 700);

    // 全部结束
    const t2 = setTimeout(() => {
      setFlyStyle(null);
      onAnimationEnd();
    }, 1800);

    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
    };
  }, [playAnimation, rewardDelta, onAnimationEnd]);

  return (
    <div ref={cardRef} className="mx-4 bg-[#f4fafe] rounded-[16px] p-4 relative overflow-hidden">
      {/* 上半部分：Locked 金额 + 钱包插画 */}
      <div className="flex justify-between items-start">
        <div>
          <p className="text-[13px] text-[#16613F] leading-[18px] tracking-[-0.23px] font-['Saans_TRIAL']">
            Locked Bonus
          </p>
          <div ref={lockedRef} className="flex items-center mt-1">
            <span className="text-[40px] font-extrabold text-[#16613F] font-[Pangram]">${displayLocked}</span>
            <img src={icLockWarning} alt="" className="w-10 h-10 ml-1.5" />
          </div>
        </div>
        <img src={icWallet} alt="" className="w-[89px] h-[89px] object-contain -mt-1" />
      </div>

      {/* 虚线分隔 */}
      <div className="border-t border-dashed border-gray-200 my-3" />

      <p className="text-[13px] text-[#16613F] leading-[18px] tracking-[-0.23px] mb-3 font-['Saans_TRIAL']">
        History always presents ${dashboard.historicalWithdrawAmount ?? 0}
      </p>

      {/* 下半部分：Available + Cash Out */}
      <div className="flex items-end justify-between bg-[#F3F3F3] rounded-[12px] p-3">
        <div ref={availableRef} className="font-['Saans_TRIAL']">
          <p className="text-[12px] leading-[16px] text-[#16613F80]">Available</p>
          <p className="text-[22px] font-medium text-[#16613F] leading-none mt-0.5">${displayAvailable}</p>
        </div>
        <button
          className="h-[34px] px-5 bg-[#399C44] rounded-full text-white text-[14px] font-semibold font-['Saans_TRIAL']"
          onClick={onCashOut}
        >
          Cash Out
        </button>
      </div>

      {/* 飞钱 Lottie 从 Locked → Available */}
      {flyStyle && moneyAnimationData && (
        <>
          <div
            className="absolute pointer-events-none z-10"
            style={{
              left: `var(--start-x)`,
              top: `var(--start-y)`,
              ...flyStyle,
              animation: `flyMoney 1.3s ease-in-out forwards`,
            }}
          >
            <Lottie
              animationData={moneyAnimationData}
              autoplay={true}
              loop={false}
              style={{ width: 80, height: 80, marginLeft: -40, marginTop: -40 }}
            />
          </div>
          <style>{`
            @keyframes flyMoney {
              0% {
                transform: translate(0, 0) scale(1.2);
                opacity: 1;
              }
              50% {
                transform: translate(
                  calc((var(--end-x) - var(--start-x)) * 0.5),
                  calc((var(--end-y) - var(--start-y)) * 0.5)
                );
                opacity: 1;
              }
              100% {
                transform: translate(
                  calc(var(--end-x) - var(--start-x)),
                  calc(var(--end-y) - var(--start-y))
                );
                opacity: 0;
              }
            }
          `}</style>
        </>
      )}
    </div>
  );
};

// ==================== 里程碑卡片（初始未邀请态） ====================

const MILESTONE_ICONS = [icMilestone1, icMilestone5, icMilestone10, icMilestoneUnlimited];

const MilestoneCard = ({ dashboard }: { dashboard: BffDashboardType }) => {
  // 优先用后端 defaultRewards，兜底用前端 MILESTONES
  const items = dashboard.defaultRewards?.length
    ? dashboard.defaultRewards.map((item, index) => ({
        icon: MILESTONE_ICONS[index] || icMilestoneUnlimited,
        label: item.title,
        reward: item.subTitle.startsWith("$") ? item.subTitle : "",
        unlimitedText: !item.title ? item.subTitle : "",
      }))
    : MILESTONES;

  return (
    <div className="bg-[#BEE9FF] rounded-[12px] flex flex-col relative" style={{ padding: "20px 12px", gap: "27px" }}>
      {items.map((milestone, index) => (
        <div key={index}>
          <div className="relative flex items-center gap-3">
            {/* 左侧头像 */}
            <div className="shrink-0 w-[50px] h-[50px] rounded-full bg-white overflow-hidden flex items-center justify-center">
              <img
                src={milestone.icon}
                alt={milestone.label ?? "unlimited"}
                className="w-[33px] h-[33px] object-cover"
              />
            </div>

            {/* 右侧信息栏 */}
            <div
              className="flex-1 bg-white rounded-[11px] px-4 flex items-center justify-between overflow-hidden"
              style={{ height: "65px" }}
            >
              {milestone.unlimitedText ? (
                <p className="text-[12px] font-semibold text-[#44BFFF] tracking-[-0.08px] leading-[14px]">
                  {milestone.unlimitedText}
                </p>
              ) : (
                <>
                  <p className="text-[15px] text-black font-medium tracking-[-0.08px] leading-[19.5px]">
                    {milestone.label}{" "}
                  </p>
                  <p className="text-[18px] font-bold text-[#44BFFF] tracking-[0.38px]">{milestone.reward}</p>
                </>
              )}
            </div>

            {/* 连接虚线（除最后一个） */}
            {index < items.length - 1 && (
              <div
                className="absolute left-[25px] top-[59px] w-[2px] h-[40px]"
                style={{
                  backgroundImage:
                    "repeating-linear-gradient(to bottom, rgba(68,191,255,0.3) 0px, rgba(68,191,255,0.3) 4px, transparent 4px, transparent 7px)",
                }}
              />
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

// ==================== Squad 列表（邀请态） ====================

const SquadList = ({ dashboard, inviteUrl }: { dashboard: BffDashboardType; inviteUrl: string }) => (
  <div className="flex flex-col gap-4 font-['Saans_TRIAL']">
    {dashboard.squadList.map((member, idx) => {
      const bgIdx = idx % SQUAD_BG_IMAGES.length;
      return (
        <SquadMemberCard
          key={`${member.relationId || member.nickname || "member"}-${idx}`}
          member={member}
          inviteUrl={inviteUrl}
          bgImage={SQUAD_BG_IMAGES[bgIdx]}
          btnColor={SQUAD_BTN_COLORS[bgIdx]}
          stageColor={SQUAD_STAGE_COLORS[bgIdx]}
          secondStageCircleColor={SQUAD_SECOND_STAGE_CIRCLE_COLORS[bgIdx]}
        />
      );
    })}
  </div>
);

// ==================== Squad 成员卡片 ====================

const SquadMemberCard = ({
  member,
  inviteUrl,
  bgImage,
  btnColor,
  stageColor,
  secondStageCircleColor,
}: {
  member: SquadMember;
  inviteUrl: string;
  bgImage: string;
  btnColor: string;
  stageColor: string;
  secondStageCircleColor: string;
}) => {
  // 根据当前阶段获取文案配置
  const stageCopy = STAGE_COPY_CONFIG[member.currentStage as "W2" | "W3" | "W4" | "W5"];

  // 根据 currentStage 动态生成 stageProgress 数组
  const stageRewardMap: Record<BffStage, number> = {
    W1: 0,
    W2: 0,
    W3: 5,
    W4: 15,
    W5: 30,
    DONE: 0,
  };

  const generateStageProgress = (): StageProgressItem[] => {
    const stages: BffStage[] = ["W1", "W2", "W3", "W4", "W5"];
    const currentStageIndex =
      member.currentStage === "DONE" ? stages.length : stages.indexOf(member.currentStage as BffStage);

    return stages.map((stage, index) => ({
      stage,
      completed: index < currentStageIndex,
      rewardAmount: stageRewardMap[stage] ?? 0,
      rewardType: stage === "W2" ? "BOOST" : "CASH",
    }));
  };

  const stageProgressList = member.stageProgress?.length
    ? member.stageProgress.map((item) => ({
        ...item,
        rewardAmount: item.rewardAmount ?? stageRewardMap[item.stage] ?? 0,
      }))
    : generateStageProgress();

  // 如果当前阶段没有配置（如 W1 或 DONE），使用后端返回的文案作为降级
  const taskText = stageCopy?.taskText || member.taskText;
  const btnText = stageCopy?.btnText || member.mainBtnText?.replace(/^👉\s*/, "") || "Poke Her";
  const shareText = member.stageReminderCopy;

  // 根据后端 activeStatus 判断状态
  const getActivityStatus = () => {
    const status = member.activeStatus || "active";
    const copy = member.activeStatusCopy || "";

    switch (status) {
      case "very_inactive":
        return { show: true, icon: icStatusLost, text: copy || "Lost > 7d", color: "#DF2727" };
      case "inactive":
        return { show: true, icon: icStatusUrgent, text: copy || "Inactive", color: "#DF2727" };
      case "idle":
        return { show: true, icon: icStatusInactive, text: copy || "Idle", color: "#FB881C" };
      case "active":
      default:
        return { show: true, icon: icStatusActive, text: copy || "Active", color: "#3EB828" };
    }
  };

  const activityStatus = getActivityStatus();

  // 处理按钮点击 - 触发分享
  const handleButtonClick = async () => {
    await shareBffLink({
      text: shareText,
      url: inviteUrl,
    });
    bpTrack(EventName.bff_poke_sent, {
      relationId: member.relationId,
      stage: member.currentStage,
    });
  };

  return (
    <div
      className="rounded-[20px] overflow-hidden relative h-[190px]"
      style={{
        backgroundImage: `url(${bgImage})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
      }}
    >
      {/* 内容区 */}
      <div className="absolute left-4 right-4 top-4 flex flex-col gap-[15px]">
        {/* 顶部：头像 + 名字/任务 + Active 状态 */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-[6px] min-w-0 flex-1">
            <img
              src={member.avatar}
              alt={member.nickname}
              className="w-[33px] h-[33px] rounded-[5px] object-cover bg-white/20 shrink-0"
            />
            <div className="min-w-0">
              <p className="text-[15px] font-medium text-white leading-[20px] tracking-[-0.23px]">{member.nickname}</p>
              <p className="text-[12px] text-white leading-[16px] tracking-[-0.23px] truncate">{taskText}</p>
            </div>
          </div>
          {activityStatus.show && (
            <div className="shrink-0 flex items-center justify-center gap-[4px] px-[9px] py-[2px] rounded-[999px] bg-white/85">
              <img src={activityStatus.icon} className="w-[12px] h-[12px] object-contain" />
              <span
                className="text-[12px] font-medium leading-[16px] tracking-[-0.23px]"
                style={{ color: activityStatus.color }}
              >
                {activityStatus.text}
              </span>
            </div>
          )}
        </div>

        {/* 阶段进度 W1-W5 */}
        <StageProgress
          stageProgress={stageProgressList}
          stageColor={stageColor}
          secondStageCircleColor={secondStageCircleColor}
        />
      </div>

      {/* 操作按钮 - 固定在卡片底部 */}
      <button
        onClick={handleButtonClick}
        className="absolute left-4 right-4 bottom-4 h-[40px] bg-white rounded-[999px] flex items-center justify-center text-[16px] font-medium leading-[21px] tracking-[-0.23px] active:bg-gray-50"
        style={{ color: btnColor }}
      >
        {btnText}
      </button>
    </div>
  );
};

// ==================== 阶段进度指示器（W1-W5） ====================

const StageProgress = ({
  stageProgress,
  stageColor,
  secondStageCircleColor,
}: {
  stageProgress: StageProgressItem[];
  stageColor: string;
  secondStageCircleColor: string;
}) => (
  <div className="flex items-start">
    {stageProgress.map((item, idx) => (
      <Fragment key={item.stage}>
        {/* 阶段间三角箭头 */}
        {idx > 0 && (
          <div className="flex-1 flex items-start justify-center pt-[11px]">
            <img src={icArrowTriangle} alt="" className="w-[8px] h-[10px]" />
          </div>
        )}

        {/* 阶段圆形 + 标签 */}
        <div className="flex-1 flex flex-col items-center gap-[6px]">
          {item.stage === "W2" ? (
            /* W2 阶段：始终显示 "1h video boost" 文案 */
            item.completed ? (
              /* W2 已完成：白色虚线圆圈 + 勾 */
              <div
                className="w-[33px] h-[33px] rounded-full flex items-center justify-center"
                style={{ border: "1.5px dashed rgba(255,255,255,0.8)" }}
              >
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                  <path
                    d="M2.5 7L5.5 10L11.5 4"
                    stroke="white"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
              </div>
            ) : (
              /* W2 进行中：彩色背景 + "1h video boost" 文案 */
              <div
                className="w-[33px] h-[33px] rounded-full flex items-center justify-center"
                style={{ backgroundColor: secondStageCircleColor }}
              >
                <span
                  className="text-white text-center font-semibold"
                  style={{
                    fontSize: "6.8px",
                    lineHeight: "7.771px",
                    letterSpacing: "-0.223px",
                  }}
                >
                  1h video
                  <br />
                  boost
                </span>
              </div>
            )
          ) : item.completed ? (
            /* 其他阶段已完成：白色虚线圆圈 + 勾 */
            <div
              className="w-[33px] h-[33px] rounded-full flex items-center justify-center"
              style={{ border: "1.5px dashed rgba(255,255,255,0.8)" }}
            >
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                <path
                  d="M2.5 7L5.5 10L11.5 4"
                  stroke="white"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
          ) : (
            /* 其他阶段未达成：白色背景圆圈 + 黑色金额 */
            <div className="w-[33px] h-[33px] rounded-full bg-white flex items-center justify-center">
              <span className="text-black text-[12px] leading-[16px] tracking-[-0.23px]">${item.rewardAmount}</span>
            </div>
          )}
          <span className="text-[12px] leading-[16px] tracking-[-0.23px]" style={{ color: stageColor }}>
            {item.stage}
          </span>
        </div>
      </Fragment>
    ))}
  </div>
);
